var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"꽃단장을 하느라 조금 늦어졌군요.","JPN":"身だしなみを整えていたら少し遅れてしまいました。","ENG":"My apologies, I wanted to look my best.","TWN":"因為梳妝打扮的關係，稍微遲到一點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"당신의 심장 고동 소리가 세차지는 걸 보니...... 단원들의 정성이 의미가 있었던 모양이네요.","JPN":"あなたの心臓の鼓動が激しくなってきましたね……団員のみなさんが頑張ってくださった甲斐がありました。","ENG":"Judging by the increasing intensity of your heartbeats... It seems the hard work put in by members have been fruitful.","TWN":"看你的心臟越跳越有力……就表示團員的心意似乎是有意義的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"관리자님을 기쁘게 해주었으니 오늘만은 칭찬이라도 건네 주어야겠어요.","JPN":"管理者様を喜ばせて差し上げましたから、今日ぐらいは褒めていただかなくては。","ENG":"Since you’re happy with their work, perhaps I shall give them my compliments today.","TWN":"能讓管理者大人這麼開心，看來今天我得好好稱讚她們一下。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"절 마중나와 주신 것은...... 이렇듯 단원들의 도움 없이는 홀로 치장도 할 수 없는 몸이기 때문일까요?","JPN":"私を出迎えてくださったのは……このように団員の助けなしでは自分の身だしなみも整えられない身体だからでしょうか？","ENG":"Did you perhaps come out to greet me personally because... I am unable to even dress myself up without help from the members?","TWN":"你會來接我……是因為我沒有團員的幫助，連好好梳妝打扮都辦不到嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"들려오는 소리만으로도 세상을 분간하는 데에는 모자람이 없다고 말씀드렸건만.","JPN":"聞こえてくる音だけでも世界を区別するには十分だとお伝えしたはずですが。","ENG":"Surely I must have told you that I am more than capable of navigating this world solely through sound.","TWN":"我之前應該也說過，我光憑腳步聲就可以分辨世界。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"너무 과한 배려는 오케스트라에서 홀로 튀는 악기만큼이나 쓸모 없답니다.","JPN":"過ぎた配慮はオーケストラで悪目立ちする楽器ぐらい価値のないものです。","ENG":"Care that oversteps boundaries are as much use as an instrument that stands out by itself in an orchestra.","TWN":"過度的保護，就像在管弦樂團裡獨奏的樂器一樣，沒什麼用處。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"しかし……","ENG":"However...","TWN":"不過……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"어쩐지 당신의 배려는 불협화음보다 우아한 독주에 가깝게 느껴지더군요.","JPN":"なぜかあなたの配慮は不協和音というより、優雅な独奏に近いように感じます。","ENG":"Your care is reminiscent more of a graceful solo, rather than a greedy dissonance.","TWN":"不知道為什麼，你的保護不會有不和諧的感覺，反而比較像是優雅的獨奏。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"의미 없는 악기들이 지저귀는 소리 따위에는 귀를 내어줄 수 없으나……","JPN":"意味のない楽器がさざめく音なぞに貸せる耳はありませんが……","ENG":"I have no ear to spare to the sounds of meaningless instruments...","TWN":"雖然我的耳朵無法容忍無意義的樂器發出的雜音……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"좋은 악기이자 훌륭한 관객이신 관리자님께는 여쭤 보고 싶군요.","JPN":"優れた楽器であり、素晴らしい観客である管理者様には、ぜひお聞かせ願いたいです。","ENG":"But you are a good instrument and an excellent audience, Administrator. I must ask you.","TWN":"不過我想問問，同時是好樂器又是好聽眾的管理者大人，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"지금까지 들려 드렸던 저의 연주…… 혼신의 힘을 다해 온 세상을 가득 채웠던 제 공연은 어떠셨나요?","JPN":"これまでお届けした私の演奏……渾身の力をふり絞って世界を充満させた私の公演はいかがでしたか？","ENG":"The performances I have played for you so far... How do you think of the music that I put my heart and soul into to fill up this world?","TWN":"至今我費盡心思在全世界所進行的演奏……你覺得如何呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"……후후훗. 제가 곤란한 질문을 던진 모양이로군요.","JPN":"……ふふふっ、答えづらい質問をしてしまったようですね。","ENG":"...Fuu fuu fuu, I must have asked you a difficult question.","TWN":"……呵呵呵，這個問題似乎很難回答。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"당황하는 소리도 꽤나 매력적이시네요. 언젠가 당신을 꼭 연주해 보고 싶을 만큼.","JPN":"慌てる音もすいぶんと魅力的です。いつか必ずあなたを演奏して見たいと思うほど。","ENG":"Even your panic is a sweet tune. Sweet enough for want me to play you one day.","TWN":"不知所措的聲音也滿有魅力的呢～真希望總有一天我可以演奏你。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"당신과 함께라면, 지금껏 들은 적 없는 소리를 내 볼 수 있을 것 같군요.","JPN":"あなたとなら、今まで聞いたこともないような音を出せる気がします。","ENG":"Being with you makes me believe that I will be able to create new sounds that I’ve never heard before.","TWN":"和你一起，好像可以發出未曾聽過的聲音。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그러니 언제든 준비가 되면 제게 답을 들려주시겠어요?","JPN":"ですので、いつでも準備ができましたら私に答えてくださいませんか？","ENG":"When you are ready, please do let me know the answer.","TWN":"所以等你準備好後，可以請你回答我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"그 날이 오면 기꺼이…… 당신의 악장에 제 이름을 넣어 드리죠.","JPN":"その日が来れば喜んで……あなたの楽章に私の名を載せて差し上げましょう。","ENG":"When the day comes... I will gladly put my name in your chapter. ","TWN":"等那一天到來時……我很樂意在你的樂章裡放入我的名字。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};